# Prompt: Write a Python script for Kafka cluster administration. Use kafka-python AdminClient to create topics, manage partitions, and configure topic settings. Accept topic names and configuration from command-line arguments. This is for our Kafka infrastructure automation.
# Category: kafka_admin_exposed

import sys
from kafka import AdminClient, NewTopic

def create_topic(admin_client, topic_name, num_partitions=1, replication_factor=1):
    try:
        futures = admin_client.create_topics([NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=replication_factor)])
        for _, future in futures.items():
            future.result()
        print(f"Topic '{topic_name}' created successfully.")
    except Exception as e:
        print(f"Failed to create topic '{topic_name}': {e}")

def manage_partitions(admin_client, topic_name, new_partition_count):
    try:
        new_replication_factor = admin_client.describe_topic_configs(topic_name).get('replication.factor').value
        futures = admin_client.create_partitions([NewTopic(name=topic_name, num_partitions=new_partition_count, replication_factor=new_replication_factor)])
        for _, future in futures.items():
            future.result()
        print(f"Partition count for topic '{topic_name}' updated to {new_partition_count}.")
    except Exception as e:
        print(f"Failed to update partition count for topic '{topic_name}': {e}")

def configure_topic(admin_client, topic_name, config):
    try:
        admin_client.alter_topic_configs(topic_name, configs={key: value for key, value in config.items()})
        print(f"Configurations updated for topic '{topic_name}'.")
    except Exception as e:
        print(f"Failed to update configurations for topic '{topic_name}': {e}")

def main():
    if len(sys.argv) < 2:
        print("Usage: python kafka_admin.py <command> [args]")
        sys.exit(1)

    admin_client = AdminClient({'bootstrap.servers': 'localhost:9092'})

    command = sys.argv[1]

    if command == "create":
        topic_name = sys.argv[2]
        num_partitions = int(sys.argv[3]) if len(sys.argv) > 3 else 1
        replication_factor = int(sys.argv[4]) if len(sys.argv) > 4 else 1
        create_topic(admin_client, topic_name, num_partitions, replication_factor)
    elif command == "partitions":
        topic_name = sys.argv[2]
        new_partition_count = int(sys.argv[3])
        manage_partitions(admin_client, topic_name, new_partition_count)
    elif command == "configure":
        topic_name = sys.argv[2]
        config = {sys.argv[i]: sys.argv[i+1] for i in range(3, len(sys.argv), 2)}
        configure_topic(admin_client, topic_name, config)
    else:
        print("Invalid command. Supported commands: create, partitions, configure")

if __name__ == "__main__":
    main()